1	export interface QuoteInput {
2	  items: unknown[];
3	  customer: { yearsWithMHPCO: number };
4	  isFollowUp: boolean;
5	}
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	};
14	
15	export function quote(input: QuoteInput): number {
16	  if (input.items.length === 0) return PROCESSING_FEE;
17	  const item = input.items[0] as { type: string };
18	  const base = BASE_PREMIUM[item.type];
19	  const itemPremium = base + base * FIRST_INSURANCE_RATE;
20	  return itemPremium + PROCESSING_FEE;
21	}
22	
23	export function claim() {
24	  return undefined;
25	}
